var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……과연.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……究竟。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"결국 자네는 시니어 코드를 사용해 시니어가 남긴 정보를 알아냈다는 건가?","JPN":"つまり、君はシニアコードを使用してシニアが残した情報を入手したということか。","ENG":"So in the end, you used the Senior Code and pulled the information he left behind?","TWN":"妳最後還是用Senior代碼查出Senior留下的情報了嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"예. 정확하게는 전 세계적인 규모로 발생할 대균열 이상 현상에 관해서죠.","JPN":"はい。正確に言えば、全世界規模で発生する大亀裂異常現象の情報です。","ENG":"Yes. Specifically about the worldwide Grand Dimension Crevice anomalies.","TWN":"對，準確來說是關於規模遍及全世界的大峽谷異常現象。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"일정 시간 동안 여섯 지부의 대균열이 확산되고 나면.","JPN":"一定時間、6つの支部の大亀裂が拡大したら……","ENG":"After the six branches' Grand Dimension Crevices expand for a set time,","TWN":"六個分部的大峽谷在一定時間內擴散之後，"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그곳으로부터 뻗어 나온 침식 뿌리가 주변의 가능성을 닥치는 대로 빨아들일 거예요.","JPN":"そこから伸びてきた侵食の根が、周辺の可能性を手当たり次第吸い込みます。","ENG":"the roots stretching out from them will suck up all the possibilities nearby they can reach.","TWN":"從那裡延伸出的侵蝕根會任意吸取周圍的可能性。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이상하군요. 만약 당신의 말 대로 전세계적인 침식 현상이 발생한다면…….","JPN":"しかし……もしその話通り、全世界的な侵食現象が発生するとしたら……","ENG":"Odd. If a global Counterside Effect is imminent as you say...","TWN":"但是很奇怪，如果照妳說的會發生遍及全世界的侵蝕現象……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어째서 해당 사실을 공표하지 않는 거죠?","JPN":"なぜその事実を発表しないのですか？","ENG":"why has it not been announced publicly?","TWN":"為什麼不公布這件事呢？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시간이 급박한들, 민간인 피해는 확연히 줄 겁니다.","JPN":"時間が足りないとはいえ、民間人の被害は確実に抑えられます。","ENG":"Even if time is tight, civilian casualties would drop noticeably.","TWN":"就算時間緊迫，平民百姓的損害也會明顯減少。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 사실을 공표해도 상부는 절 시니어의 부재를 노린 반동분자 정도로 여길 거예요.","JPN":"私が事実を公表したところで、上層部は私のことをシニアの不在を狙って反乱を起こそうとしていると思うはずです。","ENG":"Even if I went public, the higher-ups would brand me a reactionary exploiting the Senior's absence.","TWN":"即使我公布這件事，上級也只會把我當成窺伺Senior空缺的反動分子。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당장 정보의 출처가 잭슨 씨라는 걸 입증하는데 얼마나 시간이 쓰일지 모를뿐더러…….","JPN":"そもそも、情報の出処がジャクソンさんということを証明するのに、どれだけの時間がかかるかも分からないし……","ENG":"Proving that Mr. Jackson is the source would eat up who knows how much time, and...","TWN":"現在要證明情報來源是傑森，不知道要花多久時間……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앞으로 일어날 전조 현상은 결국 특정 인물의 성장을 위한 시련이라고 해요.","JPN":"これから起こる前兆現象は、結局特定の人物を成長させるための試練だそうです。","ENG":"What is coming is framed as a trial to force the growth of a certain person.","TWN":"而且之後發生的前兆現象最終是對特定人物成長的考驗。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"인과를 틀어 그걸 거스르려 해봤자, 오히려 세상의 멸망을 앞당기는 셈이죠.","JPN":"因果を捻じ曲げて逆らおうとしても、世界の滅亡を早めることにしかなりません。","ENG":"Try to twist causality to fight it, and you only speed up the world's ruin.","TWN":"就算想扭轉因果反其道而行，反倒算是加速世界的滅亡。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"특정 인물이 누구인데?","JPN":"特定の人物って誰？","ENG":"And who is that certain person?","TWN":"特定人物是誰？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"늑대라고 적혀 있긴 했는데, 자세한 설명은 없어서 저도 잘…….","JPN":"オオカミって書かれているけど、詳しい説明はなくて……","ENG":"It said the Wolf, but there were no details, so I'm not sure...","TWN":"雖然上面寫的是狼，但沒有詳細說明，我也不清楚……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어, 어쨌든! 챔버 쪽에 온 힘을 쏟아붓더라도 어떻게 될지 알 수 없다는 소리예요!","JPN":"と、とにかく！　チェンバーの方に全力を注いでも、どうなるか分からないってことです！","ENG":"A-anyway, it means even if we throw everything at Chamber, the outcome is unknown.","TWN":"總、總之！意思是就算在密室那邊傾注全力，也無法得知會怎麼樣！"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연, 이전 클리포트 게임과 비슷한 흐름이라고 생각하면 되겠군.","JPN":"なるほど。以前のクリフォトゲームと似たような流れだと思えばいいのだな。","ENG":"I see. Then it tracks with the flow we saw during the last Qliphoth Game.","TWN":"果然，應該可以想成是和先前的逆卡巴拉遊戲相似的進程。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 당장 허신이나 마왕 같은 놈들이 나온다면 다른 쪽을 걱정할 때가 아니긴 하지.","JPN":"まあ、今すぐ虚神や魔王のような奴らが出てくるとすれば、他を心配する余裕なんかないわね。","ENG":"Yeah, if a Hollow God or Demon Lord show up right now, we have bigger fish to fry than anything else.","TWN":"要是幻神或魔王之類的傢伙立刻出現，的確不是該擔心別人的時候。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 방법이 있어?","JPN":"なら、何か他に手があるの？","ENG":"But do we have a shot?","TWN":"但是有方法嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예전에 싸웠던 허신, 아니 리플레이서조차 우리 힘만으로는 버거운 상대였다고.","JPN":"前に戦った虚神……ううん、リプレイサーすらもアタシたちの力じゃ太刀打ちできなかったわ。","ENG":"Even the Hollow God we fought back then, or even the Replacer, was too much for our strength alone.","TWN":"以前戰鬥過的幻神，不，就連克隆部隊都是單憑我們的力量難以對付的對手。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그거라면 걱정 마세요. 다 방법이 있으니까!","JPN":"それなら心配いりません。手はあります！","ENG":"Then don't worry about that. There's a way!","TWN":"這點妳不用擔心，都有辦法！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"다들, 화면을 집중해 주세요!","JPN":"皆さん、画面を見てください！","ENG":"Everyone, eyes on the screen!","TWN":"大家，請注意看畫面！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"That's...","TWN":"這是？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"로터스 시니어의 필체로군. 아무래도 어떤 장치의 설계도인 듯해.","JPN":"ロータスのシニアの筆跡だな。何かの装置の設計図のようだが？","ENG":"The Lotus Senior's handwriting. Looks like a schematic for some device.","TWN":"是洛德斯Senior的筆跡，似乎是某種裝置的設計圖。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 활용해 그림자의 부상 좌표를 전환하는 장치예요.","JPN":"線路転換器は、エタニウムドライブを活用してシャドウが浮上する座標を転換する装置です。","ENG":"The Track Switcher uses an Eternium Drive to alter the emergence coordinates of Shadows.","TWN":"線路轉換器是運用永恆之金驅動器，轉換暗影浮動座標的裝置。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이걸 사용하면 공간 좌표축을 뒤틀어 뿌리의 진격 속도를 최대한 늦출 수 있죠.","JPN":"これを使えば空間座標軸を捻じ曲げて、根が伸びる速度をできるだけ遅くすることができます。","ENG":"With it, we can twist the spatial axes and slow the roots' advance as much as possible.","TWN":"使用這個的話就能扭轉空間座標軸，最大限度減緩根部的進擊速度。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"시니어 이졸데가 잘 때 슬쩍… 이 아니라, 원만한 합의를 통해 공유 받았답니다!","JPN":"シニア・イゾルデが寝てる間にこっそり……じゃなくて、合意のもとに共有してもらいました！","ENG":"I kinda swiped it when Senior Isolde was asleep– I mean, she shared it with me when we reached a friendly agreement!","TWN":"趁Senior伊索德睡覺的時候偷偷…不，是透過圓滿的協議得到共享！"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흐음… 척 보기에 아무렇게나 쓸 수 있는 물건은 아닌 것 같은데?","JPN":"へえー……見た感じ、簡単に使える物ではなさそうだけど？","ENG":"Hmm... Doesn't look like something you can just plop down and use.","TWN":"嗯哼…這看起來好像不是隨便就能用的東西耶？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이, 별거 없어요!","JPN":"いや～大したことありません！","ENG":"It's not a big deal.","TWN":"唉唷，沒什麼特別的！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그냥 동력원으로 사용할 이터니움이 조금. 아니, 많이 필요하단 것 정도…?","JPN":"ただ、動力源になるエタニウムがちょっと……いや、たくさん必要なだけで……","ENG":"You just need a little– I mean, a lot of Eternium to power it...?","TWN":"就只是需要一點，不對，是需要很多用來做為動力來源的永恆之金…？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연, 세계를 지키기 위해 합중국의 자산을 빌려달라는 셈이군.","JPN":"なるほど。世界を守るために、合衆国の資産を貸してほしいということか。","ENG":"In other words, you're asking to borrow the States' assets to protect the world.","TWN":"果然，這等於是要我們借用合眾國的資產來守護世界。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 자네의 말을 믿기에 당장은 두 가지 문제가 있어.","JPN":"だが、君の話を信用するに当たって2つ問題がある。","ENG":"But if I am to take you at your word, two problems remain for now.","TWN":"但是要相信妳的話，目前有兩個問題。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"두, 두개나 있나요?","JPN":"2つも？","ENG":"T-two problems?","TWN":"有、有兩個嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우선 첫째. 챔버의 시니어는 어떻게 미래에 벌어질 일을 알고 있었는가.","JPN":"1つ目は、チェンバーのシニアはなぜ未来の出来事について知っていたのか。","ENG":"First, how did Chamber's Senior know future events?","TWN":"首先，第一個是密室的Senior怎麼知道未來會發生的事？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고, 둘째. 임계 질량 이상의 이터니움이 모이면 그 에너지가 차원계면을 융해시키지.","JPN":"2つ目は、臨界質量を超えるエタニウムが集まると、そのエネルギーが次元界面を融解させてしまうこと。","ENG":"Second, once Eternium exceeds critical mass, its energy melts the dimension surface.","TWN":"然後第二個是，超過臨界質量的永恆之金聚集時，其能量會融解次元界面。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"유감스럽게도 설계도를 살폈을 때 문제를 해결할 요소는 보이지 않는군.","JPN":"残念ながら設計図を見た感じ、その問題を解決できそうな要素は見当たらないな。","ENG":"Unfortunately, I don't see anything in the blueprint that addresses that.","TWN":"遺憾的是，我查看設計圖的時候，沒看到能解決問題的要素。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마 말이 맞아. 차원계면은 고사하고, 그림자들을 막는데 이정도 출력으론 어림없어.","JPN":"おばんさんの言う通りよ。この程度の出力じゃ次元界面はおろか、シャドウも阻止できないわ。","ENG":"Maria is right. Forget the dimension surface, this output won't even be enough to stop Shadows.","TWN":"阿姨說得沒錯，姑且不論次元界面，單憑這點輸出根本不可能ˊ阻擋暗影。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};